// generar_263_hitos_feedback_visible.js
// CHIQUI Entre Señales — Fix: hitos de cachorro sin respuesta al tocar
//
// Síntoma: la sección de hitos aparece pero tocar un hito no hace
// nada visible.
//
// Causa raíz: toggleHito guardaba en la base y SOLO actualizaba el
// chip si la escritura era exitosa — si fallaba (por ejemplo, si la
// tabla hitos_cachorro aún no existía por no haber corrido el
// sql_261, o por un problema de conexión), el error se tragaba en
// silencio y el toque parecía muerto.
//
// Fix — nunca más un toque mudo:
// 1) UI OPTIMISTA: el chip cambia AL INSTANTE al tocarlo.
// 2) Si la base rechaza la escritura, el chip se revierte y aparece
//    un mensaje rojo en la sección ("No se pudo guardar el hito...").
// 3) El error técnico real queda en la consola del navegador
//    (console.error) para diagnóstico.
//
// IMPORTANTE: si aún no corriste sql_261_hitos_cachorro.sql en
// Supabase, hazlo — sin la tabla, los hitos seguirán sin poder
// guardarse (pero ahora al menos te lo dirá en pantalla).
//
// NOTA: este script escribe app/registro-diario/page.tsx completo e
// incluye los cambios del 260, 261 y 262.
//
// Uso:
//   node generar_263_hitos_feedback_visible.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'app/registro-diario/page.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 1 archivo escrito (incluye 260-263). git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
